(function(){'use strict';const DEFAULTS={enabled:true,cardSelector:'[data-cards]'};const externalOptions=(typeof window!=='undefined'&&((window.CarrdPluginOptions&&window.CarrdPluginOptions.cards)))||{};const CONFIG={...DEFAULTS,...externalOptions};const SELECTORS={cardItem:'theme-card-item'};const PADDING_PROPERTIES=['padding','padding-top','padding-right','padding-bottom','padding-left'];const requestFrame=window.requestAnimationFrame||(cb=>setTimeout(cb,16));const MOBILE_BREAKPOINT='(max-width: 736px)';let pendingPaddingSync=false;const isMobileViewport=()=>typeof window.matchMedia==='function'&&window.matchMedia(MOBILE_BREAKPOINT).matches;const normalizePaddingValue=value=>value.split(/\s+/).map(val=>{const num=parseFloat(val);return isNaN(num)?val:`${num}rem`;}).join(' ');const getContainerPaddingValues=style=>[style.paddingTop,style.paddingRight,style.paddingBottom,style.paddingLeft];const hasNonZeroPadding=paddingValues=>paddingValues.some(value=>parseFloat(value)!==0);function getFirstAttribute(container,attributes){for(const attribute of attributes){const value=container.getAttribute(attribute);if(value!==null&&value!==''){return value;}}return null;}function getPaddingTargets(container){const inner=container.querySelector(':scope > .wrapper > .inner');return inner?[container,inner]:[container];}function readInlinePaddingStyles(element){return PADDING_PROPERTIES.reduce((styles,property)=>{styles[property]={value:element.style.getPropertyValue(property),priority:element.style.getPropertyPriority(property)};return styles;},{});}function hasMeaningfulInlinePadding(styles){return Object.values(styles).some(({value})=>value&&parseFloat(value)!==0);}function captureAuthorPaddingStyles(element){const currentStyles=readInlinePaddingStyles(element);if(!element.__themeCardsOriginalPaddingStyles||hasMeaningfulInlinePadding(currentStyles)){element.__themeCardsOriginalPaddingStyles=currentStyles;}}function restoreAuthorPaddingStyles(element){const styles=element.__themeCardsOriginalPaddingStyles||{};PADDING_PROPERTIES.forEach(property=>{const styleState=styles[property];if(styleState&&styleState.value){element.style.setProperty(property,styleState.value,styleState.priority);}else{element.style.removeProperty(property);}});}function resetElementPadding(element){PADDING_PROPERTIES.forEach(property=>{element.style.removeProperty(property);});element.style.setProperty('padding','0px','important');}function getInheritedPadding(container){const paddingTargets=getPaddingTargets(container).reverse();for(const element of paddingTargets){const paddingValues=getContainerPaddingValues(window.getComputedStyle(element));if(hasNonZeroPadding(paddingValues)){return paddingValues.join(' ');}}return null;}function syncCardPadding(container){const paddingTargets=getPaddingTargets(container);paddingTargets.forEach(captureAuthorPaddingStyles);paddingTargets.forEach(restoreAuthorPaddingStyles);const inheritedPadding=getInheritedPadding(container);const mobile=isMobileViewport();const dataPadding=getFirstAttribute(container,['data-cards-padding','data-padding']);const dataPaddingMobile=getFirstAttribute(container,['data-cards-padding-mobile','data-padding-mobile']);if(inheritedPadding&&!mobile){container.style.setProperty('--theme-card-padding',inheritedPadding);}else if(dataPadding){container.style.setProperty('--theme-card-padding',normalizePaddingValue(dataPadding));}else if(!inheritedPadding){container.style.removeProperty('--theme-card-padding');}if(inheritedPadding&&mobile){container.style.setProperty('--theme-card-padding-mobile',inheritedPadding);}else if(dataPaddingMobile){container.style.setProperty('--theme-card-padding-mobile',normalizePaddingValue(dataPaddingMobile));}else if(!inheritedPadding){container.style.removeProperty('--theme-card-padding-mobile');}paddingTargets.forEach(resetElementPadding);}function syncAllCardPaddings(){document.querySelectorAll(`${CONFIG.cardSelector}[data-cards-initialized="true"]`).forEach(container=>syncCardPadding(container));}function scheduleAllCardPaddings(){if(pendingPaddingSync)return;pendingPaddingSync=true;requestFrame(()=>{pendingPaddingSync=false;syncAllCardPaddings();});}function bindPaddingSync(){if(window.__themeCardsPaddingSyncBound===true)return;window.__themeCardsPaddingSyncBound=true;window.addEventListener('resize',scheduleAllCardPaddings);if(typeof window.matchMedia==='function'){const mql=window.matchMedia(MOBILE_BREAKPOINT);if(typeof mql.addEventListener==='function'){mql.addEventListener('change',scheduleAllCardPaddings);}else if(typeof mql.addListener==='function'){mql.addListener(scheduleAllCardPaddings);}}}function pickCardItemBackground(cardItem,ctx){if(ctx.specificColor){cardItem.style.backgroundColor=ctx.specificColor;}else if(ctx.dataColor){cardItem.style.backgroundColor=ctx.dataColor;}else if(ctx.backgroundColor&&ctx.backgroundColor!=='rgba(0, 0, 0, 0)'&&ctx.backgroundColor!=='transparent'){cardItem.style.backgroundColor=ctx.backgroundColor;}}function applyCardItemBorder(cardItem,ctx){if(ctx.borderRadius&&ctx.borderRadius!=='0px'){cardItem.style.setProperty('--theme-card-border-radius',ctx.borderRadius);}if(ctx.borderTopWidth&&ctx.borderTopWidth!=='0px'&&ctx.borderTopStyle!=='none'){cardItem.style.borderWidth=ctx.borderTopWidth;cardItem.style.borderStyle=ctx.borderTopStyle;cardItem.style.borderColor=ctx.specificBorderColor||ctx.borderTopColor;}if(ctx.boxShadow&&ctx.boxShadow!=='none'){cardItem.style.boxShadow=ctx.boxShadow;}}function applyCardItemBackgroundImage(cardItem,ctx){if(!ctx.dataColor&&!ctx.specificColor&&ctx.backgroundImage&&ctx.backgroundImage!=='none'){cardItem.style.backgroundImage=ctx.backgroundImage;cardItem.style.backgroundPosition=ctx.backgroundPosition;cardItem.style.backgroundRepeat=ctx.backgroundRepeat;cardItem.style.backgroundSize=ctx.backgroundSize;}}function buildColumnCardItem(column,index,ctx){if(column.querySelector('.theme-card-item, .card-item'))return;const cardItem=document.createElement('div');cardItem.classList.add(SELECTORS.cardItem);const itemCtx={...ctx,specificColor:getFirstAttribute(ctx.container,[`data-cards-color-${index + 1}`,`data-color-${index + 1}`]),specificBorderColor:getFirstAttribute(ctx.container,[`data-cards-border-color-${index + 1}`,`data-border-color-${index + 1}`])};pickCardItemBackground(cardItem,itemCtx);applyCardItemBorder(cardItem,itemCtx);applyCardItemBackgroundImage(cardItem,itemCtx);while(column.firstChild){cardItem.appendChild(column.firstChild);}column.appendChild(cardItem);}function init(){if(CONFIG.enabled===false)return;bindPaddingSync();const cardContainers=document.querySelectorAll(CONFIG.cardSelector);cardContainers.forEach(container=>{if(container.getAttribute('data-cards-initialized')==='true')return;container.setAttribute('data-cards-initialized','true');const style=window.getComputedStyle(container);const backgroundColor=style.backgroundColor;const borderRadius=style.borderRadius;const borderTopWidth=style.borderTopWidth;const borderTopStyle=style.borderTopStyle;const borderTopColor=style.borderTopColor;const boxShadow=style.boxShadow;const backgroundImage=style.backgroundImage;const backgroundPosition=style.backgroundPosition;const backgroundRepeat=style.backgroundRepeat;const backgroundSize=style.backgroundSize;const dataColor=getFirstAttribute(container,['data-cards-color','data-color']);syncCardPadding(container);container.style.setProperty('border','none','important');container.style.setProperty('box-shadow','none','important');if(!dataColor){container.style.setProperty('background-color','transparent','important');container.style.setProperty('background','none','important');}const inner=container.querySelector('.inner');if(!inner)return;const columns=Array.from(inner.children);const ctx={container,dataColor,backgroundColor,borderRadius,borderTopWidth,borderTopStyle,borderTopColor,boxShadow,backgroundImage,backgroundPosition,backgroundRepeat,backgroundSize};columns.forEach((column,index)=>buildColumnCardItem(column,index,ctx));});}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',init);}else{init();}})();